class KthLargest {
public:
    KthLargest(int k, vector<int>& nums) {
        n = nums.size();
        k--;
        if (k == 0) {
            kthLargest = nums[n - 1];
        } else {
            int low = 0;
            int high = n - 1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (nums[mid] > kthLargest) {
                    kthLargest = nums[mid];
                    low = mid + 1;
            } else {
                         high = mid - 1;
            }
        }
    }

    int findKthLargest(vector<int>& nums) {
        return kthLargest;
    }
};
